// ─── Helpers ──────────────────────────────────

export function getDisciplineByName(nom) {
  return DISCIPLINES.find(d => d.nom === nom);
}

export function getPowersForLevel(discipline, niveau) {
  return discipline.pouvoirs.filter(p => p.niveau === niveau);
}

export function getDisciplineNames() {
  return DISCIPLINES.map(d => d.nom);
}
